import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const p=JSON.parse('{"title":"佛香阁","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/foxiang-ge.md","filePath":"landmarks/summer-palace/foxiang-ge.md","lastUpdated":1784720050000}'),n={name:"landmarks/summer-palace/foxiang-ge.md"};function o(i,t,s,d,g,h){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="佛香阁" tabindex="-1">佛香阁 <a class="header-anchor" href="#佛香阁" aria-label="Permalink to &quot;佛香阁&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1677607219708-24b1cb001415?w=1200&amp;q=80" alt="佛香阁"></p><blockquote><p>&quot;阁凌碧宇天香近，佛现金身海气澄。&quot; —— 万寿山巅的金顶，颐和园的天际线</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>佛香阁雄踞万寿山前山中央，是颐和园的标志性建筑，也是全园的最高点与构图中心。无论你站在昆明湖畔、<a href="/beijing-travel-guide/landmarks/summer-palace/changlang.html">长廊</a>之中，还是远处的西堤，抬眼望去，那一抹金碧辉煌的三重檐楼阁永远是视线的终点。</p><p>整座建筑群依山而建，从湖岸的&quot;云辉玉宇&quot;牌楼起，经排云门、<a href="/beijing-travel-guide/landmarks/summer-palace/paiyun-dian.html">排云殿</a>、德辉殿，层层递进，直至山巅的佛香阁与智慧海，形成一条气势磅礴的中轴线。</p><p>佛香阁始建于乾隆年间，&quot;佛香&quot;之名取自佛教经典，意为&quot;佛之香气，普熏十方&quot;。1860年佛香阁遭英法联军焚毁，现存建筑为光绪十七年至二十年（1891-1894年）重建，耗银七十八万两，是颐和园重建工程中最大的单项工程。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">清乾隆年间</td><td style="text-align:left;">原拟建九层&quot;延寿宝塔&quot;，建至第八层时奉旨改塔为阁</td></tr><tr><td style="text-align:left;">咸丰十年（1860）</td><td style="text-align:left;">遭英法联军焚毁，仅余台基与西侧铜亭</td></tr><tr><td style="text-align:left;">光绪十七年至二十年（1891-1894）</td><td style="text-align:left;">重建，耗银78万两，为全园重建工程之最</td></tr><tr><td style="text-align:left;">1924年</td><td style="text-align:left;">随颐和园对外开放，成为游必登临之处</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>阁高</strong></td><td style="text-align:left;">41米，八面三层四重檐</td></tr><tr><td style="text-align:left;"><strong>台基</strong></td><td style="text-align:left;">建于20米高的石砌方形城台之上</td></tr><tr><td style="text-align:left;"><strong>结构</strong></td><td style="text-align:left;">八根铁梨木擎天柱支撑全阁</td></tr><tr><td style="text-align:left;"><strong>供奉</strong></td><td style="text-align:left;">明代铜铸千手千眼观音立像，高5米，重约5吨，通体贴金</td></tr><tr><td style="text-align:left;"><strong>周边胜迹</strong></td><td style="text-align:left;">宝云阁（铜亭）、转轮藏、智慧海、众香界琉璃牌坊</td></tr><tr><td style="text-align:left;"><strong>门票</strong></td><td style="text-align:left;">园中园，联票含或另购10元</td></tr></tbody></table><p>佛香阁三重檐覆黄绿琉璃瓦，阁内二层以上设回廊，可凭栏环眺。阁内供奉的千手观音为明代万历年间铜铸，法相庄严，是园内最珍贵的佛教文物。</p><p>阁西侧山坡上还藏着一座&quot;宝云阁&quot;——通体以青铜铸成、仿木构重檐的铜亭，重逾二十万斤，铸造于乾隆二十年（1755年），历经大火而毫发无损，堪称冶金史上的奇迹。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="九层宝塔为何变成三层高阁" tabindex="-1">九层宝塔为何变成三层高阁 <a class="header-anchor" href="#九层宝塔为何变成三层高阁" aria-label="Permalink to &quot;九层宝塔为何变成三层高阁&quot;">​</a></h3><p>乾隆为母祝寿，本欲在万寿山建一座九层延寿宝塔，工程建到第八层时却骤然叫停。民间传说有二：一说是乾隆登高远眺，发现西边玉泉山上已有玉峰塔矗立，两塔遥相对峙，风水上犯了忌讳；二说是匠人估算九层塔工期钱粮无底，借故停工。</p><p>无论真相如何，拆塔建阁的结果反而成就了园林史上最成功的&quot;改稿&quot;——宝塔虽高却显单调，而三层佛香阁收分有致、翼角飞翘，与昆明湖的开阔水面相得益彰，成为&quot;借景西山、俯瞰全湖&quot;的绝佳视点。</p><h3 id="大火烧不毁的铜亭" tabindex="-1">大火烧不毁的铜亭 <a class="header-anchor" href="#大火烧不毁的铜亭" aria-label="Permalink to &quot;大火烧不毁的铜亭&quot;">​</a></h3><p>1860年英法联军纵火焚园，万寿山上的木构建筑几乎悉数化为灰烬，佛香阁亦未能幸免。然而阁西的宝云阁铜亭通体青铜铸成，烈火只能熏黑它的表面，却奈何不得分毫。</p><p>劫后余生的铜亭与重建后的佛香阁比邻而立，一个记着毁灭，一个见证重生。有趣的是，铜亭的门窗在1900年八国联军劫掠时被拆走流落海外，直到百年后才部分回归——一座铜亭的流散与团圆，又是另一段国运的缩影。</p><h3 id="七十八万两白银堆出的地标" tabindex="-1">七十八万两白银堆出的地标 <a class="header-anchor" href="#七十八万两白银堆出的地标" aria-label="Permalink to &quot;七十八万两白银堆出的地标&quot;">​</a></h3><p>光绪朝重建佛香阁，整整用了四年（1891-1894）。据清宫档案，工程耗银七十八万两，是全园重建中花钱最多的单项，比<a href="/beijing-travel-guide/landmarks/summer-palace/dehe-yuan.html">德和园</a>大戏楼还多出数万两。八根铁梨木大柱、四重檐琉璃瓦、五百级登山磴道……这些银子从哪里来？相当一部分正是挪用的海军经费。</p><p>佛香阁金顶在阳光下有多耀眼，甲午年的海面上就有多黯淡——这座地标，从诞生之日起就背着历史的债。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>登顶俯瞰</strong>：凭阁回廊环眺，昆明湖、十七孔桥、西堤六桥尽收眼底，天气晴好时玉泉山塔与西山连绵如黛——这是中国造园&quot;借景&quot;手法最直观的教科书。</li><li><strong>千手观音</strong>：阁内明代铜铸千手千眼观音立像，五米高通体贴金，法相慈祥，为园内佛教艺术之冠。</li><li><strong>建筑中轴线</strong>：从云辉玉宇牌楼到佛香阁的登山步道，本身就是一件作品，建议放慢脚步体会&quot;步移景异&quot;。</li><li><strong>宝云阁铜亭</strong>：全铜铸造的&quot;金殿&quot;，连门窗纹饰都仿木构而成，别处罕见。</li><li><strong>琉璃牌坊众香界</strong>：山巅智慧海前的五色琉璃牌坊，不施寸木，外壁雕有千余尊琉璃小佛，与佛香阁同框极入画。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>阁前回廊</strong>：二层回廊是拍昆明湖全景的最佳高度，上午9点前光线柔和、游人稀少。</li><li><strong>南湖岛对望</strong>：想拍佛香阁标准像，机位不在阁前而在湖对岸——南湖岛涵虚堂前、西堤柳桥畔皆可。</li><li><strong>中轴透视</strong>：从排云门前仰拍，牌楼、殿宇、高阁层层叠起，一张照片收入整座前山。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li>佛香阁为园中园，需持联票或另购10元门票；登山台阶较陡，老人小孩量力而行。</li><li>登顶的最佳时间是上午9点前或下午4点后，顺光拍湖、游人亦少。</li><li>想拍佛香阁全景，最佳机位不在阁前，而在昆明湖对岸的南湖岛或西堤——&quot;横看成岭侧成峰&quot;。</li><li>参观完佛香阁，可顺中轴线下行至<a href="/beijing-travel-guide/landmarks/summer-palace/paiyun-dian.html">排云殿</a>，再转入<a href="/beijing-travel-guide/landmarks/summer-palace/changlang.html">长廊</a>，动线一气呵成。</li><li>阁内禁止对佛像使用闪光灯，既是文物保护，也是对信仰的尊重。</li><li>登山途中别只顾埋头爬台阶——中途回望，每一层高度都有不一样的湖景。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：佛香阁需要单独买票吗？</strong></p><p>佛香阁属园中园，单独购票10元；持颐和园联票可直接登阁，建议直接买联票。</p><p><strong>Q：登佛香阁累吗？</strong></p><p>从排云门到阁顶有数百级台阶，坡度较陡，正常体力约20-30分钟；老人小孩建议慢行，中途亭子可歇脚。</p><p><strong>Q：佛香阁里面能看到什么？</strong></p><p>一层供奉明代铜铸千手千眼观音立像，二层以上设回廊可凭栏环眺，昆明湖、十七孔桥、玉泉山塔尽收眼底。</p><p><strong>Q：佛香阁和排云殿、智慧海怎么串联？</strong></p><p>三者在同一条中轴线上：自排云门进<a href="/beijing-travel-guide/landmarks/summer-palace/paiyun-dian.html">排云殿</a>，拾级登佛香阁，再上行至智慧海与琉璃牌坊，全程1-1.5小时，是颐和园最经典的登山动线。</p><hr><p><strong>📍 位置</strong>：万寿山前山中央，全园制高点 <strong>⏱️ 建议游览</strong>：1小时（含登山） <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园概览</a></p>',40)])])}const m=a(n,[["render",o]]);export{p as __pageData,m as default};
